import React, { useState, useEffect } from 'react';

const records = [
    { id: 1, name: 'adam', age: 25 },
    { id: 2, name: 'james', age: 30 },
    { id: 3, name: 'nick', age: 28 },
    { id: 4, name: 'john', age: 29 }
];

const sortableColumns = ['id', 'name', 'age'];

const tableComponent = () => {
    const [data, setData] = useState(records);
    const [filterText, setFilterText] = useState('');
    const [sortColumn, setSortColumn] = useState(null);
    const [sortDirection, setSortDirection] = useState('asc');

    useEffect(() => {
        let filteredData = data;

        if (filterText) {
            filteredData = data.filter(item => 
                item.name.toLowerCase().includes(filterText.toLowerCase())
            );
        }

        if (sortColumn) {
            filteredData.sort((a, b) => {
                if (a[sortColumn] < b[sortColumn]) return sortDirection === 'asc' ? -1 : 1;
                if (a[sortColumn] > b[sortColumn]) return sortDirection === 'asc' ? 1 : -1;
                return 0;
            });
        }

        setData(filteredData);
    }, [filterText, sortColumn, sortDirection, data]);

    const handleSort = (column) => {
        if (sortColumn === column) {
            setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
        } else {
            setSortColumn(column);
            setSortDirection('asc');
        }
    };

    const handleFilterChange = (e) => {
        setFilterText(e.target.value);
    };

    return (
        <div>
            <input
                type="text"
                placeholder="filter by name"
                value={filterText}
                onChange={handleFilterChange}
            />
            <table>
                <thead>
                    <tr>
                        <th>id</th>
                        <th>
                            name
                            <button onClick={() => handleSort('name')}>sort</button>
                        </th
